# Auto-generated: embeds public/index.html for serverless environments
HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8" />\n<meta name="viewport" content="width=device-width, initial-scale=1.0" />\n<title>BharatTrust AI — Marketplace Intelligence Control Room</title>\n<link rel="preconnect" href="https://fonts.googleapis.com" />\n<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />\n<link href="https://fonts.googleapis.com/css2?family=Sora:wght@400;500;600;700;800&family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@400;500;700&display=swap" rel="stylesheet" />\n<style>\n:root{\n  --ink:#0A0E1A; --panel:#111728; --panel-2:#0E1422; --line:#1E2740;\n  --txt:#E6ECF7; --muted:#8A97B4; --dim:#5A668A;\n  --trust:#34D399; --risk:#FB7185; --info:#38BDF8; --orch:#A78BFA; --saffron:#F59E0B;\n  --good:#34D399; --warn:#FBBF24; --bad:#FB7185;\n  --mono:\'JetBrains Mono\',monospace; --disp:\'Sora\',sans-serif; --body:\'Inter\',sans-serif;\n}\n*{box-sizing:border-box}\nhtml,body{margin:0;padding:0}\nbody{\n  background:\n    radial-gradient(1200px 600px at 80% -10%, rgba(167,139,250,.10), transparent 60%),\n    radial-gradient(900px 500px at 0% 110%, rgba(56,189,248,.08), transparent 55%),\n    var(--ink);\n  color:var(--txt); font-family:var(--body);\n  -webkit-font-smoothing:antialiased; min-height:100vh;\n}\na{color:inherit}\n::selection{background:rgba(167,139,250,.3)}\n.mono{font-family:var(--mono)}\n\n/* ---------- top bar ---------- */\nheader.topbar{\n  display:flex; align-items:center; gap:24px;\n  padding:14px 26px; border-bottom:1px solid var(--line);\n  position:sticky; top:0; z-index:50;\n  background:rgba(10,14,26,.82); backdrop-filter:blur(14px);\n}\n.brand{display:flex; align-items:center; gap:11px; font-family:var(--disp); font-weight:800; font-size:19px; letter-spacing:-.3px}\n.brand .mark{\n  width:30px;height:30px;border-radius:9px;\n  background:linear-gradient(140deg,var(--saffron),var(--trust) 55%,var(--info));\n  display:grid;place-items:center;color:#06101e;font-weight:800;font-size:15px;\n  box-shadow:0 0 22px rgba(52,211,153,.35);\n}\n.brand b{color:var(--saffron)}\nnav.views{display:flex; gap:4px; margin-left:8px}\nnav.views button{\n  font-family:var(--disp); font-weight:600; font-size:13.5px; color:var(--muted);\n  background:transparent; border:1px solid transparent; padding:8px 15px; border-radius:9px; cursor:pointer;\n  transition:.15s;\n}\nnav.views button:hover{color:var(--txt)}\nnav.views button.active{color:var(--txt); background:var(--panel); border-color:var(--line)}\n.live-pill{\n  margin-left:auto; display:flex; align-items:center; gap:8px; font-size:12px; color:var(--muted);\n  font-family:var(--mono); padding:6px 12px; border:1px solid var(--line); border-radius:999px; background:var(--panel-2);\n}\n.dot{width:8px;height:8px;border-radius:50%;background:var(--trust);box-shadow:0 0 0 0 rgba(52,211,153,.6);animation:pulse 1.8s infinite}\n@keyframes pulse{0%{box-shadow:0 0 0 0 rgba(52,211,153,.5)}70%{box-shadow:0 0 0 8px rgba(52,211,153,0)}100%{box-shadow:0 0 0 0 rgba(52,211,153,0)}}\n\nmain{max-width:1320px;margin:0 auto;padding:26px}\n.view{display:none}\n.view.active{display:block; animation:fade .35s ease}\n@keyframes fade{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:none}}\n\n.eyebrow{font-family:var(--mono);font-size:11.5px;letter-spacing:2px;text-transform:uppercase;color:var(--orch)}\nh1.title{font-family:var(--disp);font-weight:800;font-size:30px;letter-spacing:-.6px;margin:7px 0 6px}\n.sub{color:var(--muted);font-size:14.5px;max-width:680px;line-height:1.55}\n\n/* ---------- search / picks ---------- */\n.searchwrap{margin:22px 0 8px;display:flex;gap:10px;flex-wrap:wrap}\n.searchbox{flex:1;min-width:280px;display:flex;align-items:center;gap:10px;background:var(--panel);border:1px solid var(--line);border-radius:13px;padding:12px 16px}\n.searchbox input{flex:1;background:transparent;border:none;outline:none;color:var(--txt);font-size:15px;font-family:var(--body)}\n.searchbox input::placeholder{color:var(--dim)}\n.btn{font-family:var(--disp);font-weight:700;font-size:14px;border:none;border-radius:11px;padding:12px 22px;cursor:pointer;transition:.15s;color:#06101e;background:linear-gradient(135deg,var(--trust),var(--info))}\n.btn:hover{filter:brightness(1.08);transform:translateY(-1px)}\n.btn:disabled{opacity:.5;cursor:not-allowed;transform:none}\n.btn.ghost{background:var(--panel);color:var(--txt);border:1px solid var(--line)}\n.picks{display:flex;gap:9px;flex-wrap:wrap;margin:6px 0 4px}\n.pick{\n  font-size:12.5px;font-family:var(--mono);color:var(--muted);\n  background:var(--panel-2);border:1px solid var(--line);border-radius:999px;padding:7px 13px;cursor:pointer;transition:.15s;\n  display:flex;align-items:center;gap:7px\n}\n.pick:hover{border-color:var(--orch);color:var(--txt)}\n.pick .flag{width:7px;height:7px;border-radius:50%}\n\n/* ---------- theatre ---------- */\n.theatre{display:grid;grid-template-columns:1.05fr 1fr;gap:18px;margin-top:18px}\n@media(max-width:980px){.theatre{grid-template-columns:1fr}}\n.card{background:linear-gradient(180deg,var(--panel),var(--panel-2));border:1px solid var(--line);border-radius:16px;padding:18px}\n.card h3{font-family:var(--disp);font-weight:700;font-size:14px;margin:0 0 4px;display:flex;align-items:center;gap:8px}\n.card .hint{color:var(--dim);font-size:12px;font-family:var(--mono);margin-bottom:12px}\n\n/* orchestrator graph */\n#graph{width:100%;height:430px;display:block}\n.gnode-label{font-family:var(--disp);font-weight:600;font-size:11px;fill:var(--muted)}\n.gnode-metric{font-family:var(--mono);font-weight:700;font-size:12px;fill:var(--txt)}\n\n/* console */\n.console{font-family:var(--mono);font-size:12.5px;line-height:1.7;height:430px;overflow-y:auto;padding-right:8px}\n.console::-webkit-scrollbar{width:7px}.console::-webkit-scrollbar-thumb{background:var(--line);border-radius:8px}\n.logline{display:flex;gap:9px;align-items:flex-start;opacity:0;animation:slidein .25s forwards}\n@keyframes slidein{to{opacity:1}}\n.logline .tag{flex-shrink:0;font-weight:700;padding:0 6px;border-radius:5px;font-size:10.5px;letter-spacing:.4px;margin-top:1px}\n.tag.orch{background:rgba(167,139,250,.16);color:var(--orch)}\n.tag.disp{background:rgba(56,189,248,.14);color:var(--info)}\n.tag.reason{background:rgba(138,151,180,.12);color:var(--muted)}\n.tag.res{background:rgba(52,211,153,.14);color:var(--trust)}\n.tag.dec{background:rgba(245,158,11,.16);color:var(--saffron)}\n.logline .txt{color:var(--txt)}\n.logline .txt.dim{color:var(--muted)}\n.cursor{display:inline-block;width:8px;height:14px;background:var(--trust);margin-left:3px;animation:blink 1s steps(2) infinite;vertical-align:middle}\n@keyframes blink{0%,50%{opacity:1}51%,100%{opacity:0}}\n\n/* agent result strip */\n.agentgrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(168px,1fr));gap:11px;margin-top:16px}\n.agentcard{background:var(--panel-2);border:1px solid var(--line);border-radius:13px;padding:13px;opacity:.4;transition:.4s;position:relative;overflow:hidden}\n.agentcard.live{opacity:1;border-color:var(--info)}\n.agentcard.done{opacity:1}\n.agentcard .an{font-family:var(--disp);font-weight:600;font-size:12px;color:var(--muted);display:flex;align-items:center;gap:7px;margin-bottom:9px}\n.agentcard .av{font-family:var(--mono);font-weight:700;font-size:23px;letter-spacing:-.5px}\n.agentcard .au{font-size:11px;color:var(--dim);font-family:var(--mono)}\n.agentcard .spin{width:13px;height:13px;border:2px solid var(--line);border-top-color:var(--info);border-radius:50%;animation:rot .7s linear infinite}\n@keyframes rot{to{transform:rotate(360deg)}}\n.v-good{color:var(--good)} .v-warn{color:var(--warn)} .v-bad{color:var(--bad)} .v-info{color:var(--info)}\n.agentcard .reasons{margin-top:9px;font-size:11px;line-height:1.55;color:var(--muted);display:none}\n.agentcard.done .reasons{display:block}\n.agentcard .reasons div{display:flex;gap:6px;margin-bottom:2px}\n.agentcard .reasons .b{color:var(--dim)}\n\n/* decision verdict */\n#verdict{margin-top:18px;display:none}\n.verdict-inner{display:grid;grid-template-columns:200px 1fr;gap:20px;align-items:center}\n@media(max-width:680px){.verdict-inner{grid-template-columns:1fr}}\n.gauge-wrap{text-align:center}\n.gauge-num{font-family:var(--disp);font-weight:800;font-size:42px;letter-spacing:-1.5px}\n.gauge-band{font-family:var(--mono);font-size:12px;letter-spacing:1px;text-transform:uppercase}\n.verdict-stamp{font-family:var(--disp);font-weight:800;font-size:22px;letter-spacing:-.5px;margin-bottom:6px}\n.verdict-action{color:var(--muted);font-size:13.5px;margin-bottom:14px}\n.bar{display:flex;align-items:center;gap:10px;margin-bottom:7px;font-size:12px}\n.bar .bl{width:108px;color:var(--muted);font-family:var(--mono);font-size:11px;text-align:right;flex-shrink:0}\n.bar .bt{flex:1;height:7px;background:var(--line);border-radius:6px;overflow:hidden}\n.bar .bf{height:100%;border-radius:6px;width:0;transition:width 1s ease}\n.bar .bv{width:42px;font-family:var(--mono);font-weight:700;font-size:11.5px}\n\n/* ---------- admin ops ---------- */\n.kpis{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:13px;margin-top:18px}\n.kpi{background:linear-gradient(180deg,var(--panel),var(--panel-2));border:1px solid var(--line);border-radius:14px;padding:15px}\n.kpi .l{font-size:11px;color:var(--muted);font-family:var(--mono);letter-spacing:.5px;text-transform:uppercase}\n.kpi .v{font-family:var(--disp);font-weight:800;font-size:27px;letter-spacing:-1px;margin-top:5px}\n.kpi .d{font-size:11px;color:var(--dim);margin-top:2px}\n.ops{display:grid;grid-template-columns:1.15fr 1fr;gap:18px;margin-top:18px}\n@media(max-width:980px){.ops{grid-template-columns:1fr}}\n.feed{height:520px;overflow-y:auto;padding-right:6px}\n.feed::-webkit-scrollbar{width:7px}.feed::-webkit-scrollbar-thumb{background:var(--line);border-radius:8px}\n.evt{display:flex;gap:11px;padding:11px 12px;border:1px solid var(--line);border-radius:12px;margin-bottom:9px;background:var(--panel-2);opacity:0;animation:evtin .4s forwards}\n@keyframes evtin{from{opacity:0;transform:translateX(-10px)}to{opacity:1;transform:none}}\n.evt .sev{width:3px;border-radius:3px;flex-shrink:0}\n.sev-critical{background:var(--risk)} .sev-high{background:#fb923c} .sev-medium{background:var(--warn)} .sev-info{background:var(--trust)}\n.evt .em{flex:1}\n.evt .emt{font-size:13px;font-weight:600;margin-bottom:2px}\n.evt .emd{font-size:11.5px;color:var(--muted);font-family:var(--mono)}\n.evt .ema{font-size:11px;color:var(--dim);margin-top:3px}\n.evt .escore{font-family:var(--mono);font-weight:700;font-size:15px;flex-shrink:0;text-align:right}\n.evt .eag{font-size:10px;color:var(--dim);text-align:right;font-family:var(--mono)}\n\n/* india map */\n#indiaMap{width:100%;height:520px}\n.mapdot{animation:dotpop .5s ease}\n@keyframes dotpop{from{r:0;opacity:0}to{opacity:.95}}\n.city-label{font-family:var(--mono);font-size:9px;fill:var(--dim)}\n.india-path{fill:rgba(56,189,248,.05);stroke:rgba(138,151,180,.35);stroke-width:1.2}\n\n/* seller studio */\n.studio{display:grid;grid-template-columns:300px 1fr;gap:18px;margin-top:18px}\n@media(max-width:820px){.studio{grid-template-columns:1fr}}\n.sellerlist{height:560px;overflow-y:auto;padding-right:6px}\n.sellerlist::-webkit-scrollbar{width:7px}.sellerlist::-webkit-scrollbar-thumb{background:var(--line);border-radius:8px}\n.srow{display:flex;justify-content:space-between;align-items:center;padding:11px 13px;border:1px solid var(--line);border-radius:11px;margin-bottom:8px;cursor:pointer;transition:.15s;background:var(--panel-2)}\n.srow:hover{border-color:var(--orch)}\n.srow.sel{border-color:var(--trust);background:rgba(52,211,153,.06)}\n.srow .sn{font-weight:600;font-size:13.5px}\n.srow .ss{font-size:11px;color:var(--dim);font-family:var(--mono)}\n.srow .sc{font-family:var(--mono);font-weight:700;font-size:16px}\n.chartbox{height:256px;margin-top:8px}\n.loadingmsg{color:var(--muted);font-family:var(--mono);font-size:12.5px;display:flex;align-items:center;gap:9px;padding:30px 0;justify-content:center}\n.footer{margin-top:40px;padding:20px 0;border-top:1px solid var(--line);color:var(--dim);font-size:12px;font-family:var(--mono);text-align:center}\n.empty{color:var(--dim);font-family:var(--mono);font-size:12.5px;text-align:center;padding:40px 0}\n</style>\n</head>\n<body>\n<header class="topbar">\n  <div class="brand"><div class="mark">B</div>Bharat<b>Trust</b>&nbsp;AI</div>\n  <nav class="views">\n    <button data-view="orchestrator" class="active">Orchestrator</button>\n    <button data-view="admin">Admin Ops</button>\n    <button data-view="seller">Seller Studio</button>\n  </nav>\n  <div class="live-pill"><span class="dot"></span><span id="connStatus">agents online</span></div>\n</header>\n\n<main>\n  <!-- ============ ORCHESTRATOR THEATRE ============ -->\n  <section class="view active" id="view-orchestrator">\n    <div class="eyebrow">Live agent orchestration</div>\n    <h1 class="title">Watch the agents decide.</h1>\n    <p class="sub">Enter a product and the Orchestrator dispatches seven specialist agents in sequence — each one reasons in the open, returns a computed score, and the Decision Engine fuses them into a verdict. Nothing here is pre-baked; every number comes from the model running over the live marketplace.</p>\n\n    <div class="searchwrap">\n      <div class="searchbox">\n        <span class="mono" style="color:var(--dim)">›</span>\n        <input id="q" placeholder="Search a listing to evaluate — e.g. Nike, Samsung, shoes…" />\n      </div>\n      <button class="btn" id="runBtn">Run agents</button>\n    </div>\n    <div class="picks" id="picks"></div>\n\n    <div class="theatre">\n      <div class="card">\n        <h3>🧠 Orchestrator graph</h3>\n        <div class="hint" id="graphHint">Idle — pick a listing to dispatch the pipeline</div>\n        <svg id="graph" viewBox="0 0 520 430" xmlns="http://www.w3.org/2000/svg"></svg>\n      </div>\n      <div class="card">\n        <h3>⌗ Reasoning console</h3>\n        <div class="hint">Streamed over Server-Sent Events from the backend</div>\n        <div class="console" id="console"><div class="empty">awaiting dispatch…</div></div>\n      </div>\n    </div>\n\n    <div class="agentgrid" id="agentgrid"></div>\n\n    <div class="card" id="verdict">\n      <h3>⚖️ Decision Engine</h3>\n      <div class="hint">Weighted fusion of all agent signals</div>\n      <div class="verdict-inner">\n        <div class="gauge-wrap">\n          <svg width="170" height="170" viewBox="0 0 170 170">\n            <circle cx="85" cy="85" r="68" fill="none" stroke="var(--line)" stroke-width="13"/>\n            <circle id="gaugeArc" cx="85" cy="85" r="68" fill="none" stroke="var(--trust)" stroke-width="13"\n              stroke-linecap="round" stroke-dasharray="427" stroke-dashoffset="427"\n              transform="rotate(-90 85 85)" style="transition:stroke-dashoffset 1.1s ease,stroke .4s"/>\n            <text id="gaugeNum" x="85" y="80" text-anchor="middle" class="gauge-num" fill="var(--txt)">—</text>\n            <text id="gaugeBand" x="85" y="103" text-anchor="middle" class="gauge-band" fill="var(--muted)"></text>\n          </svg>\n        </div>\n        <div>\n          <div class="verdict-stamp" id="vStamp">—</div>\n          <div class="verdict-action" id="vAction"></div>\n          <div id="vBars"></div>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <!-- ============ ADMIN OPS ============ -->\n  <section class="view" id="view-admin">\n    <div class="eyebrow">Marketplace operations</div>\n    <h1 class="title">Ops control room</h1>\n    <p class="sub">A live feed of autonomous agent findings across the marketplace — fraud rings, counterfeit listings, and return-risk interventions surface here the moment the agents flag them.</p>\n    <div class="kpis" id="kpis"></div>\n    <div class="ops">\n      <div class="card">\n        <h3>📡 Live agent event stream</h3>\n        <div class="hint">SSE · autonomous findings, newest first</div>\n        <div class="feed" id="feed"><div class="empty">connecting to event stream…</div></div>\n      </div>\n      <div class="card">\n        <h3>🗺️ Risk map of India</h3>\n        <div class="hint" id="mapHint">flagged sellers plotted as events arrive</div>\n        <svg id="indiaMap" viewBox="0 0 600 680" xmlns="http://www.w3.org/2000/svg"></svg>\n      </div>\n    </div>\n  </section>\n\n  <!-- ============ SELLER STUDIO ============ -->\n  <section class="view" id="view-seller">\n    <div class="eyebrow">Seller intelligence</div>\n    <h1 class="title">Seller studio</h1>\n    <p class="sub">Pick any seller to run a full trust evaluation — the orchestrator scores them across six signals and explains every point.</p>\n    <div class="studio">\n      <div class="card" style="padding:14px">\n        <h3>Sellers</h3>\n        <div class="hint">ranked by current trust score</div>\n        <div class="sellerlist" id="sellerlist"><div class="empty">loading…</div></div>\n      </div>\n      <div class="card" id="sellerDetail">\n        <div class="empty">Select a seller to evaluate.</div>\n      </div>\n    </div>\n  </section>\n\n  <div class="footer">BharatTrust AI · 9 autonomous agents · scores computed live over 500 sellers / 3,000 listings · FastAPI + SSE</div>\n</main>\n<script>\nwindow.API_BASE = window.API_BASE || "";\nconst API = (p) => (window.API_BASE || "") + p;\nconst $ = (s, r=document) => r.querySelector(s);\nconst el = (t, c, h) => { const e=document.createElement(t); if(c)e.className=c; if(h!=null)e.innerHTML=h; return e; };\n\n/* ---------------- view switching ---------------- */\ndocument.querySelectorAll("nav.views button").forEach(b=>{\n  b.onclick = ()=>{\n    document.querySelectorAll("nav.views button").forEach(x=>x.classList.remove("active"));\n    b.classList.add("active");\n    document.querySelectorAll(".view").forEach(v=>v.classList.remove("active"));\n    $("#view-"+b.dataset.view).classList.add("active");\n    if(b.dataset.view==="admin") startAdmin();\n    if(b.dataset.view==="seller") loadSellers();\n  };\n});\n\n/* ---------------- orchestrator graph ---------------- */\nconst SVGNS="http://www.w3.org/2000/svg";\nconst TONE={good:"var(--good)",warn:"var(--warn)",bad:"var(--bad)",info:"var(--info)"};\nlet nodePos={};\nfunction svgEl(t,attrs){const e=document.createElementNS(SVGNS,t);for(const k in attrs)e.setAttribute(k,attrs[k]);return e;}\n\nfunction drawGraph(pipeline){\n  const g=$("#graph"); g.innerHTML="";\n  nodePos={};\n  const ox=80, oy=215, ax=270, dx=455;\n  const n=pipeline.length;\n  const top=30, bottom=400, step=(bottom-top)/(n-1);\n  // edges first\n  pipeline.forEach((a,i)=>{\n    const ay=top+i*step; nodePos[a.agent]={x:ax,y:ay};\n    g.appendChild(svgEl("line",{id:"e1-"+a.agent,x1:ox,y1:oy,x2:ax,y2:ay,stroke:"var(--line)","stroke-width":1.4}));\n    g.appendChild(svgEl("line",{id:"e2-"+a.agent,x1:ax,y1:ay,x2:dx,y2:oy,stroke:"var(--line)","stroke-width":1.2}));\n  });\n  // orchestrator node\n  g.appendChild(svgEl("circle",{cx:ox,cy:oy,r:26,fill:"rgba(167,139,250,.14)",stroke:"var(--orch)","stroke-width":2}));\n  const ot=svgEl("text",{x:ox,y:oy-32,"text-anchor":"middle",class:"gnode-label",fill:"var(--orch)"});ot.textContent="ORCHESTRATOR";g.appendChild(ot);\n  const oi=svgEl("text",{x:ox,y:oy+5,"text-anchor":"middle","font-size":18});oi.textContent="🧠";g.appendChild(oi);\n  // decision node\n  g.appendChild(svgEl("circle",{id:"decNode",cx:dx,cy:oy,r:24,fill:"rgba(245,158,11,.10)",stroke:"var(--line)","stroke-width":2}));\n  const dt=svgEl("text",{x:dx,y:oy-30,"text-anchor":"middle",class:"gnode-label"});dt.textContent="DECISION";g.appendChild(dt);\n  const di=svgEl("text",{x:dx,y:oy+5,"text-anchor":"middle","font-size":16});di.textContent="⚖️";g.appendChild(di);\n  // agent nodes\n  pipeline.forEach((a)=>{\n    const p=nodePos[a.agent];\n    g.appendChild(svgEl("circle",{id:"node-"+a.agent,cx:p.x,cy:p.y,r:13,fill:"var(--panel)",stroke:"var(--line)","stroke-width":1.6}));\n    const lb=svgEl("text",{x:p.x+22,y:p.y-2,class:"gnode-label"});lb.textContent=a.label;g.appendChild(lb);\n    const mt=svgEl("text",{id:"gm-"+a.agent,x:p.x+22,y:p.y+12,class:"gnode-metric",fill:"var(--dim)"});mt.textContent="";g.appendChild(mt);\n  });\n}\nfunction setNode(agent,state,tone){\n  const node=$("#node-"+agent), e1=$("#e1-"+agent);\n  if(!node)return;\n  if(state==="live"){\n    node.setAttribute("stroke","var(--info)");node.setAttribute("stroke-width",2.4);\n    node.setAttribute("fill","rgba(56,189,248,.18)");\n    e1.setAttribute("stroke","var(--info)");e1.setAttribute("stroke-width",2);\n    e1.setAttribute("stroke-dasharray","5 5");\n    let off=0; node._anim=setInterval(()=>{off=(off+1)%10;e1.setAttribute("stroke-dashoffset",off);},60);\n    node.setAttribute("r",16);\n  }else if(state==="done"){\n    clearInterval(node._anim);\n    const col=TONE[tone]||"var(--trust)";\n    node.setAttribute("stroke",col);node.setAttribute("fill",col);node.setAttribute("r",13);node.setAttribute("stroke-width",1.6);\n    e1.setAttribute("stroke",col);e1.removeAttribute("stroke-dasharray");e1.setAttribute("stroke-width",1.6);\n    $("#e2-"+agent).setAttribute("stroke","rgba(245,158,11,.4)");\n  }\n}\n\n/* ---------------- agent cards ---------------- */\nconst AGENTS_ORDER=["seller_monitoring","authenticity","fraud","review_intelligence","return_prediction","price_intelligence","logistics"];\nfunction buildAgentCards(pipeline){\n  const grid=$("#agentgrid"); grid.innerHTML="";\n  pipeline.forEach(a=>{\n    const c=el("div","agentcard");c.id="ac-"+a.agent;\n    c.innerHTML=`<div class="an"><span>${iconFor(a.agent)}</span>${a.label}</div>\n      <div class="av" id="av-${a.agent}">—</div><div class="au" id="au-${a.agent}">idle</div>\n      <div class="reasons" id="ar-${a.agent}"></div>`;\n    grid.appendChild(c);\n  });\n}\nfunction iconFor(a){return {seller_monitoring:"🛡️",authenticity:"🏷️",fraud:"🚨",review_intelligence:"💬",return_prediction:"📦",price_intelligence:"💸",logistics:"🚚"}[a]||"●";}\n\n/* ---------------- console ---------------- */\nlet consoleEl, typingLine=null;\nfunction logLine(tagClass,tagTxt,txt,dim){\n  if(typingLine){typingLine.querySelector(".cursor")?.remove();typingLine=null;}\n  const line=el("div","logline");\n  line.innerHTML=`<span class="tag ${tagClass}">${tagTxt}</span><span class="txt ${dim?\'dim\':\'\'}">${txt}</span>`;\n  consoleEl.appendChild(line);\n  consoleEl.scrollTop=consoleEl.scrollHeight;\n  return line;\n}\n\n/* ---------------- run orchestration ---------------- */\nlet esOrch=null;\nfunction runOrchestration(productId, productName){\n  if(esOrch){esOrch.close();esOrch=null;}\n  $("#runBtn").disabled=true;\n  consoleEl=$("#console"); consoleEl.innerHTML="";\n  $("#verdict").style.display="none";\n  $("#graphHint").textContent="Dispatching pipeline for: "+(productName||("#"+productId));\n\n  const url=API(`/api/orchestrate/stream?product_id=${productId}&pace=0.55`);\n  const es=new EventSource(url); esOrch=es;\n\n  es.addEventListener("orchestrator",e=>{\n    const d=JSON.parse(e.data);\n    drawGraph(d.pipeline); buildAgentCards(d.pipeline);\n    logLine("orch","ORCH",`Intent received → <b>${d.product.name}</b> · seller “${d.seller.name}” (${d.seller.state})`);\n    logLine("orch","ORCH",`Dispatching ${d.pipeline.length} agents…`,true);\n  });\n  es.addEventListener("dispatch",e=>{\n    const d=JSON.parse(e.data);\n    setNode(d.agent,"live");\n    const c=$("#ac-"+d.agent); if(c)c.classList.add("live");\n    $("#au-"+d.agent).innerHTML=\'<span class="spin"></span>\';\n    logLine("disp","DISPATCH",`→ ${d.label} agent`);\n  });\n  es.addEventListener("reasoning",e=>{\n    const d=JSON.parse(e.data);\n    const l=logLine("reason","·",`${d.step}`,true);\n    l.querySelector(".txt").insertAdjacentHTML("beforeend",\'<span class="cursor"></span>\');\n    typingLine=l;\n  });\n  es.addEventListener("result",e=>{\n    const d=JSON.parse(e.data);\n    const m=d.metric, tone=m.tone;\n    setNode(d.agent,"done",tone);\n    $("#gm-"+d.agent).textContent=fmtMetric(m);\n    $("#gm-"+d.agent).setAttribute("fill",TONE[tone]||"var(--txt)");\n    const c=$("#ac-"+d.agent); c.classList.remove("live"); c.classList.add("done");\n    const av=$("#av-"+d.agent); av.textContent=fmtMetric(m); av.className="av v-"+tone;\n    $("#au-"+d.agent).textContent=m.unit;\n    const ar=$("#ar-"+d.agent); ar.innerHTML=d.reasons.slice(0,3).map(r=>`<div><span class="b">›</span><span>${r}</span></div>`).join("");\n    logLine("res","RESULT",`<b>${d.label}</b> → ${d.headline}`);\n  });\n  es.addEventListener("decision",e=>{\n    const d=JSON.parse(e.data);\n    if(d.phase==="fusing"){\n      $("#decNode").setAttribute("stroke","var(--saffron)");\n      $("#decNode").setAttribute("fill","rgba(245,158,11,.2)");\n      logLine("dec","DECIDE","Decision Engine fusing all signals…",true);\n    }else{\n      renderVerdict(d);\n      logLine("dec","VERDICT",`<b>${d.verdict}</b> · overall ${d.overall} (${d.band})`);\n    }\n  });\n  es.addEventListener("done",()=>{ es.close(); esOrch=null; $("#runBtn").disabled=false; $("#graphHint").textContent="Pipeline complete"; });\n  es.onerror=()=>{ es.close(); esOrch=null; $("#runBtn").disabled=false;\n    if(!consoleEl.children.length) logLine("dec","ERROR","Stream interrupted — is the backend running?"); };\n}\nfunction fmtMetric(m){\n  if(m.unit.startsWith("₹")||m.unit.includes("ETA")) return (m.unit.startsWith("₹")?"₹":"")+Number(m.value).toLocaleString("en-IN")+(m.unit.includes("ETA")?"d":"");\n  return Math.round(m.value);\n}\n\n/* ---------------- verdict ---------------- */\nfunction renderVerdict(d){\n  $("#verdict").style.display="block";\n  $("#verdict").scrollIntoView({behavior:"smooth",block:"nearest"});\n  const arc=$("#gaugeArc"), circ=427;\n  const col=d.overall>=75?"var(--good)":d.overall>=55?"var(--warn)":"var(--bad)";\n  arc.setAttribute("stroke",col);\n  setTimeout(()=>arc.setAttribute("stroke-dashoffset",circ*(1-d.overall/100)),60);\n  $("#gaugeNum").textContent=d.overall; $("#gaugeNum").setAttribute("fill",col);\n  $("#gaugeBand").textContent=d.band;\n  const stamp=$("#vStamp"); stamp.textContent=d.verdict;\n  stamp.style.color=d.verdict.startsWith("RECOMMEND W")?"var(--warn)":d.verdict==="SUPPRESS"?"var(--bad)":"var(--good)";\n  $("#vAction").textContent=d.action;\n  const bars=$("#vBars"); bars.innerHTML="";\n  const riskKeys={"Fraud risk":1,"Return risk":1};\n  Object.entries(d.breakdown).forEach(([k,v])=>{\n    const isRisk=riskKeys[k];\n    const col=isRisk?(v<30?"var(--good)":v<60?"var(--warn)":"var(--bad)"):(v>=70?"var(--good)":v>=45?"var(--warn)":"var(--bad)");\n    const row=el("div","bar");\n    row.innerHTML=`<div class="bl">${k}</div><div class="bt"><div class="bf" style="background:${col}"></div></div><div class="bv" style="color:${col}">${v}</div>`;\n    bars.appendChild(row);\n    setTimeout(()=>row.querySelector(".bf").style.width=Math.min(100,v)+"%",80);\n  });\n}\n\n/* ---------------- picks + search ---------------- */\nlet allPicks=[];\nasync function loadPicks(){\n  try{\n    const r=await fetch(API("/api/orchestrate/picks")); const d=await r.json();\n    allPicks=d.picks; const box=$("#picks"); box.innerHTML="";\n    d.picks.forEach(p=>{\n      const counterfeit = p.mrp && p.price/p.mrp<0.5;\n      const chip=el("div","pick");\n      chip.innerHTML=`<span class="flag" style="background:${counterfeit?\'var(--risk)\':\'var(--trust)\'}"></span>${p.brand} · ${p.name.length>22?p.name.slice(0,22)+"…":p.name}`;\n      chip.onclick=()=>runOrchestration(p.id,p.name);\n      box.appendChild(chip);\n    });\n  }catch(e){ $("#picks").innerHTML=\'<span class="empty">backend offline — start it with run.bat</span>\'; }\n}\n$("#runBtn").onclick=()=>{\n  const q=$("#q").value.trim().toLowerCase();\n  if(!q){ if(allPicks[0])runOrchestration(allPicks[0].id,allPicks[0].name); return; }\n  const hit=allPicks.find(p=>(p.name+" "+p.brand+" "+p.category).toLowerCase().includes(q));\n  if(hit) runOrchestration(hit.id,hit.name);\n  else if(allPicks[0]) runOrchestration(allPicks[0].id,allPicks[0].name);\n};\n$("#q").addEventListener("keydown",e=>{if(e.key==="Enter")$("#runBtn").click();});\n\n/* ---------------- ADMIN OPS ---------------- */\nlet adminStarted=false, esEvents=null, mapDots=0;\nasync function startAdmin(){\n  if(adminStarted) return; adminStarted=true;\n  drawIndia();\n  try{\n    const o=await (await fetch(API("/api/analytics/overview"))).json();\n    const kpis=[\n      ["Marketplace health",o.marketplace_health,"weighted trust index","var(--trust)"],\n      ["Sellers monitored",o.sellers,"live behavioural scan","var(--info)"],\n      ["Flagged sellers",o.flagged_sellers,"risk ≥ 50","var(--risk)"],\n      ["Avg fraud risk",o.avg_fraud_risk+"%","across marketplace","var(--warn)"],\n      ["Return rate",o.return_rate_pct+"%",o.returns+" of "+o.orders+" orders","var(--info)"],\n      ["Listings","3,000","authenticity-scanned","var(--trust)"],\n    ];\n    const box=$("#kpis"); box.innerHTML="";\n    kpis.forEach(k=>box.appendChild(el("div","kpi",`<div class="l">${k[0]}</div><div class="v" style="color:${k[3]}">${k[1]}</div><div class="d">${k[2]}</div>`)));\n  }catch(e){}\n  // live event stream\n  const feed=$("#feed"); feed.innerHTML="";\n  const es=new EventSource(API("/api/events/stream?interval=1.5")); esEvents=es;\n  es.addEventListener("event",e=>{\n    const d=JSON.parse(e.data); addEvent(d); plotDot(d);\n  });\n  es.onerror=()=>{ if(!feed.children.length)feed.innerHTML=\'<div class="empty">event stream unavailable — backend offline</div>\'; };\n}\nfunction addEvent(d){\n  const feed=$("#feed");\n  if(feed.querySelector(".empty"))feed.innerHTML="";\n  const col=d.severity==="critical"?"var(--risk)":d.severity==="high"?"#fb923c":d.severity==="medium"?"var(--warn)":"var(--trust)";\n  const ev=el("div","evt");\n  ev.innerHTML=`<div class="sev sev-${d.severity}"></div>\n    <div class="em"><div class="emt">${d.message}</div>\n      ${d.detail?`<div class="emd">${d.detail}</div>`:""}\n      ${d.action?`<div class="ema">↳ ${d.action}</div>`:""}</div>\n    <div><div class="escore" style="color:${col}">${Math.round(d.score)}</div><div class="eag">${d.agent}</div></div>`;\n  feed.insertBefore(ev,feed.firstChild);\n  while(feed.children.length>40)feed.removeChild(feed.lastChild);\n}\n\n/* ---------------- India map ---------------- */\nconst INDIA_BORDER=[[74,34.5],[78.5,32.5],[80.5,30.5],[83,29],[88,27],[89.5,26],[92,27.5],[95.5,27.5],[97,28],[96,24],[94,23.5],[93.5,22],[91.5,22.5],[89.5,22],[88,21.5],[87,20.5],[85,19],[82.5,17],[80.3,15.5],[80.3,13.1],[79.8,11.5],[79,10],[77.5,8.1],[76.5,8.9],[75,11.5],[74.5,14.5],[73.5,16],[72.9,19.1],[72.6,21.5],[70,21],[68.5,22.5],[69.5,24],[70.5,27],[72.5,29],[74.5,31],[74,32.5]];\nconst CITIES=[["Delhi",28.6,77.2],["Mumbai",19.07,72.87],["Bengaluru",12.97,77.59],["Kolkata",22.57,88.36],["Chennai",13.08,80.27],["Hyderabad",17.38,78.48]];\nfunction proj(lat,lng){return {x:(lng-68)*20, y:(37-lat)*22.67};}\nfunction drawIndia(){\n  const m=$("#indiaMap"); m.innerHTML="";\n  const pts=INDIA_BORDER.map(([lng,lat])=>{const p=proj(lat,lng);return p.x+","+p.y;}).join(" ");\n  m.appendChild(svgEl("polygon",{points:pts,class:"india-path"}));\n  CITIES.forEach(([name,lat,lng])=>{\n    const p=proj(lat,lng);\n    m.appendChild(svgEl("circle",{cx:p.x,cy:p.y,r:2,fill:"var(--dim)"}));\n    const t=svgEl("text",{x:p.x+5,y:p.y+3,class:"city-label"});t.textContent=name;m.appendChild(t);\n  });\n}\nfunction plotDot(d){\n  if(d.lat==null||d.lng==null)return;\n  const m=$("#indiaMap"); const p=proj(d.lat,d.lng);\n  const col=d.severity==="critical"?"var(--risk)":d.severity==="high"?"#fb923c":d.severity==="medium"?"var(--warn)":"var(--trust)";\n  const c=svgEl("circle",{cx:p.x,cy:p.y,r:Math.max(4,Math.min(10,d.score/12)),fill:col,"fill-opacity":.55,stroke:col,"stroke-width":1.2,class:"mapdot"});\n  m.appendChild(c); mapDots++;\n  $("#mapHint").textContent=`${mapDots} flagged sellers plotted`;\n  // pulse ring for critical\n  if(d.severity==="critical"){\n    const ring=svgEl("circle",{cx:p.x,cy:p.y,r:5,fill:"none",stroke:col,"stroke-width":1.5});\n    const an=document.createElementNS(SVGNS,"animate");\n    an.setAttribute("attributeName","r");an.setAttribute("from","5");an.setAttribute("to","20");an.setAttribute("dur","1.6s");an.setAttribute("repeatCount","indefinite");\n    const an2=document.createElementNS(SVGNS,"animate");\n    an2.setAttribute("attributeName","opacity");an2.setAttribute("from","0.8");an2.setAttribute("to","0");an2.setAttribute("dur","1.6s");an2.setAttribute("repeatCount","indefinite");\n    ring.appendChild(an);ring.appendChild(an2);m.appendChild(ring);\n  }\n  while(m.querySelectorAll(".mapdot").length>60)m.querySelector(".mapdot").remove();\n}\n\n/* ---------------- SELLER STUDIO ---------------- */\nlet sellersLoaded=false;\nasync function loadSellers(){\n  if(sellersLoaded)return; sellersLoaded=true;\n  try{\n    const d=await (await fetch(API("/api/analytics/seller-ranking?limit=40"))).json();\n    const list=[...(d.top||[]),...(d.bottom||[])];\n    const box=$("#sellerlist"); box.innerHTML="";\n    list.forEach(s=>{\n      const score=s.overall??s.trust_score??s.score;\n      const col=score>=75?"var(--good)":score>=55?"var(--warn)":"var(--bad)";\n      const row=el("div","srow");\n      row.innerHTML=`<div><div class="sn">${s.seller_name||s.name||("Seller "+s.seller_id)}</div><div class="ss">${s.state||s.band||""}</div></div><div class="sc" style="color:${col}">${Math.round(score)}</div>`;\n      row.onclick=()=>{document.querySelectorAll(".srow").forEach(r=>r.classList.remove("sel"));row.classList.add("sel");evalSeller(s.seller_id||s.id);};\n      box.appendChild(row);\n    });\n  }catch(e){ $("#sellerlist").innerHTML=\'<div class="empty">backend offline</div>\'; }\n}\nasync function evalSeller(id){\n  const d=$("#sellerDetail");\n  d.innerHTML=\'<div class="loadingmsg"><span class="spin"></span>orchestrator evaluating seller…</div>\';\n  let r;\n  try{ r=await (await fetch(API("/api/sellers/"+id+"/trust"))).json(); }\n  catch(e){ d.innerHTML=\'<div class="empty">could not reach the backend</div>\'; return; }\n  const comp=r.components||{};\n  const col=r.overall>=75?"var(--good)":r.overall>=55?"var(--warn)":"var(--bad)";\n  d.innerHTML=`<h3>⚖️ ${r.seller_name||("Seller "+id)} · trust evaluation</h3>\n    <div class="hint">six-signal fusion, computed live</div>\n    <div style="display:flex;align-items:center;gap:24px;flex-wrap:wrap;margin:6px 0 10px">\n      <div style="font-family:var(--disp);font-weight:800;font-size:46px;color:${col};letter-spacing:-1.5px">${r.overall}<span style="font-size:18px;color:var(--dim)">/100</span></div>\n      <div style="font-family:var(--mono);font-size:13px;color:${col};text-transform:uppercase;letter-spacing:1px">${r.band}</div>\n    </div>\n    <div class="chartbox" id="radarBox"></div>\n    <div style="margin-top:14px"><div class="hint">why this score</div>\n      ${(r.reasons||[]).slice(0,6).map(x=>`<div style="font-size:12.5px;color:var(--muted);margin-bottom:4px;font-family:var(--mono)">› ${x}</div>`).join("")}\n    </div>`;\n  try{ drawRadar($("#radarBox"), comp); }catch(e){ /* radar is decoration; never block the data */ }\n}\n// dependency-free SVG radar (risk axes inverted so outward = better everywhere)\nfunction drawRadar(box, comp){\n  const entries=Object.entries(comp);\n  if(!entries.length) return;\n  const riskAxes={fraud_risk:1,return_risk:1};\n  const W=460,H=256,cx=W/2,cy=H/2,R=84,n=entries.length;\n  const ang=i=>-Math.PI/2 + i*2*Math.PI/n;\n  const pt=(i,frac)=>[cx+Math.cos(ang(i))*R*frac, cy+Math.sin(ang(i))*R*frac];\n  let s=`<svg viewBox="0 0 ${W} ${H}" width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">`;\n  // grid rings + spokes\n  [0.33,0.66,1].forEach(f=>{\n    const ring=entries.map((_,i)=>pt(i,f).join(",")).join(" ");\n    s+=`<polygon points="${ring}" fill="none" stroke="rgba(138,151,180,.16)" stroke-width="1"/>`;\n  });\n  entries.forEach((_,i)=>{const [x,y]=pt(i,1);s+=`<line x1="${cx}" y1="${cy}" x2="${x}" y2="${y}" stroke="rgba(138,151,180,.14)"/>`;});\n  // value polygon (invert risk axes so the shape reads "bigger = healthier")\n  const vals=entries.map(([k,v])=>riskAxes[k]?100-v:v);\n  const poly=entries.map((_,i)=>pt(i,Math.max(0.04,Math.min(1,vals[i]/100))).join(",")).join(" ");\n  s+=`<polygon points="${poly}" fill="rgba(52,211,153,.16)" stroke="var(--trust)" stroke-width="2"/>`;\n  entries.forEach((_,i)=>{const [x,y]=pt(i,Math.max(0.04,Math.min(1,vals[i]/100)));\n    s+=`<circle cx="${x}" cy="${y}" r="3" fill="var(--trust)"/>`;});\n  // labels with raw values (risk axes show their true score, marked ↓)\n  entries.forEach(([k,v],i)=>{\n    const [x,y]=pt(i,1.22);\n    const anchor=Math.abs(Math.cos(ang(i)))<0.3?"middle":(Math.cos(ang(i))>0?"start":"end");\n    const lbl=k.replace("_"," ")+(riskAxes[k]?" ↓":"");\n    s+=`<text x="${x}" y="${y}" text-anchor="${anchor}" font-family="var(--mono)" font-size="10" fill="#8A97B4">${lbl}</text>`;\n    s+=`<text x="${x}" y="${y+12}" text-anchor="${anchor}" font-family="var(--mono)" font-size="10.5" font-weight="700" fill="${riskAxes[k]?(v<30?\'#34D399\':v<60?\'#FBBF24\':\'#FB7185\'):(v>=70?\'#34D399\':v>=45?\'#FBBF24\':\'#FB7185\')}">${Math.round(v)}</text>`;\n  });\n  s+="</svg>";\n  box.innerHTML=s;\n}\n\n/* ---------------- boot ---------------- */\nloadPicks();\n</script>\n</body>\n</html>\n'
